'use strict';

console.info(
  '%cAnime %cEXT%c\n%cDesarrollado por Chiki & Chikiqwe',
  "font-family:'Alice',sans-serif;color:white;font-size:1.5rem;font-weight:bold;",
  "font-family:'Alice',sans-serif;color:#00BFFF;font-size:1.5rem;font-weight:bold;",
  "font-family:'Alice',sans-serif;color:white;font-size:1.5rem;font-weight:bold;",
  'color:#888;font-size:1rem;',
);

/* ============================================================
 * CONFIGURACIÓN
 * ============================================================ */
const CONFIG = {
  API_BASE: '/api',
  STATUS_URL: '/status',
  VERSION_URL: '/app/v',
  BLUR: { scale: 0.1, fps: 60 },
  API: {
    LAST: '/anime/last',
    LIST: '/anime/list',
    DESCRIPTION: '/api/description',
    EPISODES: '/api/episodes',
    IMAGE_PROXY: (url) => `/image?url=${encodeURIComponent(url)}`,
    FCM_USER: '/api/user',
  },
  DB: {
    FAVORITES: { name: 'FavoritosDB', version: 1, store: 'favoritos' },
    CACHE: { name: 'AnimeCacheDB', version: 3, store: 'precached' },
  },
  EPISODE_SOURCES: ['FLV', 'TIO', 'ANIMEYTX'],
};

/* ============================================================
 * STATE
 * ============================================================ */
const State = {
  config: {},       // { id, uid, totalEp, ep, title }
  serverList: [],
  hls: null,
  blobUrl: null,
  wakeLock: null,
  mirror: 1,
  fullscreen: false,
  progressTimer: null,
  mainInitDone: false,
  // Blur
  animFrame: null,
  blurActive: false,
  blurLooping: false,
  blurFrame: false,
  blurLastTs: 0,
  blurBuffers: ['', ''],
  blurBufIdx: 0,
  // Draggable
  drag: { x: 0, y: 0 },
};

/* ============================================================
 * UTILS
 * ============================================================ */
const Utils = {
  el: (id) => document.getElementById(id),
  qs: (sel, r = document) => r.querySelector(sel),
  qsa: (sel, r = document) => Array.from(r.querySelectorAll(sel)),
  versionToCode: (v) => { const p = v.split('.').map(Number); return p[0] * 100 + p[1] * 10 + p[2]; },

  normalize(text) {
    if (!text) return '';
    return text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, ' ').trim();
  },
  cleanTitle: (t) => (t ? t.trim() : ''),
  getPageParam() {
    const raw = new URLSearchParams(window.location.search).get('page');
    return /^[1-9]\d*$/.test(raw) ? parseInt(raw, 10) : 1;
  },
  paginate(items, page, perPage = 24) {
    return items.slice((page - 1) * perPage, page * perPage);
  },
  findByUId(uid) {
    return State.fullAnimeList?.find((a) => a.unit_id === uid) ?? null;
  },
  debounce(fn, delay) {
    let timer;
    return (...args) => {
      clearTimeout(timer);
      timer = setTimeout(() => fn(...args), delay);
    };
  },
};
/* ============================================================
 * DATABASE  (IndexedDB — progress / history / cache)
 * ============================================================ */
const DB = {
  _promise: null,

  open() {
    if (this._promise) return this._promise;
    this._promise = new Promise((resolve, reject) => {
      const req = indexedDB.open(CONFIG.DB.name, CONFIG.DB.version);
      req.onerror = () => reject(req.error);
      req.onsuccess = () => resolve(req.result);
      req.onupgradeneeded = (e) => {
        const db = e.target.result;
        for (const [store, key] of [['precached', 'url'], ['progress', 'slug'], ['history', 'uid']]) {
          if (!db.objectStoreNames.contains(store)) {
            db.createObjectStore(store, { keyPath: key });
          }
        }
      };
    });
    return this._promise;
  },

  async put(store, value) {
    const db = await this.open();
    const tx = db.transaction(store, 'readwrite');
    return new Promise((res, rej) => {
      const r = tx.objectStore(store).put(value);
      r.onsuccess = () => res();
      r.onerror = () => rej(r.error);
    });
  },

  async get(store, key) {
    const db = await this.open();
    return new Promise((res, rej) => {
      const r = db.transaction(store, 'readonly').objectStore(store).get(key);
      r.onsuccess = () => res(r.result);
      r.onerror = () => rej(r.error);
    });
  },

  async delete(store, key) {
    const db = await this.open();
    return new Promise((res, rej) => {
      const r = db.transaction(store, 'readwrite').objectStore(store).delete(key);
      r.onsuccess = () => res();
      r.onerror = () => rej(r.error);
    });
  },

  // --- Progress helpers ---
  async saveProgress(slug, time) {
    await this.put('progress', { slug, currentTime: time, updatedAt: Date.now() });
  },

  async loadProgress(slug) {
    const r = await this.get('progress', slug);
    return r?.currentTime ?? 0;
  },

  // --- History helpers ---
  async addHistory(uid) {
    await this.put('history', { uid, addedAt: Date.now() });
  },
  _openFavorites() {
    return new Promise((resolve, reject) => {
      const req = indexedDB.open(CONFIG.DB.FAVORITES.name, CONFIG.DB.FAVORITES.version);
      req.onerror = () => reject('Error abriendo FavoritosDB');
      req.onsuccess = () => resolve(req.result);
      req.onupgradeneeded = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains(CONFIG.DB.FAVORITES.store)) {
          db.createObjectStore(CONFIG.DB.FAVORITES.store, { keyPath: 'title' });
        }
      };
    });
  },

  async _favTx(mode) {
    const db = await this._openFavorites();
    const tx = db.transaction(CONFIG.DB.FAVORITES.store, mode);
    return tx.objectStore(CONFIG.DB.FAVORITES.store);
  },

  async favoriteAdd(title) {
    const store = await this._favTx('readwrite');
    return new Promise((res, rej) => {
      const r = store.add({ title });
      r.onsuccess = () => res(true);
      r.onerror = () => rej('Error al agregar favorito');
    });
  },

  async favoriteRemove(title) {
    const store = await this._favTx('readwrite');
    return new Promise((res, rej) => {
      const r = store.delete(title);
      r.onsuccess = () => res(true);
      r.onerror = () => rej('Error al eliminar favorito');
    });
  },

  async favoriteExists(title) {
    const store = await this._favTx('readonly');
    return new Promise((res, rej) => {
      const r = store.get(title);
      r.onsuccess = () => res(!!r.result);
      r.onerror = () => rej('Error al verificar favorito');
    });
  },

  async favoriteLoadAll() {
    const store = await this._favTx('readonly');
    return new Promise((res, rej) => {
      const r = store.getAll();
      r.onsuccess = () => res(r.result.map((i) => i.title));
      r.onerror = () => rej('Error al cargar favoritos');
    });
  },

  _openCache() {
    if (State.dbCache) return Promise.resolve(State.dbCache);
    return new Promise((resolve, reject) => {
      const req = indexedDB.open(CONFIG.DB.CACHE.name, CONFIG.DB.CACHE.version);
      req.onerror = () => reject(req.error);
      req.onsuccess = () => { State.dbCache = req.result; resolve(req.result); };
      req.onupgradeneeded = (e) => {
        const db = e.target.result;
        for (const store of [CONFIG.DB.CACHE.store, 'progress', 'history']) {
          if (!db.objectStoreNames.contains(store)) {
            const keyPath = store === 'history' ? 'uid' : store === 'progress' ? 'slug' : 'url';
            db.createObjectStore(store, { keyPath });
          }
        }
      };
    });
  },

  async getHistory() {
    const db = await this._openCache();
    return new Promise((res, rej) => {
      const r = db.transaction('history', 'readonly').objectStore('history').getAll();
      r.onsuccess = () => res(r.result ?? []);
      r.onerror = () => rej(r.error);
    });
  },

  async removeHistory(uid) {
    const db = await this._openCache();
    return new Promise((res, rej) => {
      const r = db.transaction('history', 'readwrite').objectStore('history').delete(uid);
      r.onsuccess = () => res();
      r.onerror = () => rej(r.error);
    });
  },
};


/* ============================================================
 * NETWORK  (online guard + mainInit)
 * ============================================================ */
const Network = {
  async check() {
    try {
      const resp = await fetch(CONFIG.STATUS_URL, { method: 'GET', cache: 'no-store' });
      if (resp.ok) {
        Utils.el('mainContent')?.style.setProperty('display', 'block');
        Utils.el('offlineOverlay')?.classList.add('hidden');
        if (!State.mainInitDone) { State.mainInitDone = true; Player.init(); }
        setTimeout(() => Network.check(), 5000);
      } else {
        this._offline();
      }
    } catch {
      this._offline();
    }
  },

  _offline() {
    const vid = Utils.el('player');
    vid?.pause();
    Utils.el('mainContent')?.style.setProperty('display', 'none');
    Utils.el('offlineOverlay')?.classList.remove('hidden');
    setTimeout(() => Network.check(), 5000);
  },
};

/* ============================================================
 * FULLSCREEN
 * ============================================================ */
const Fullscreen = {
  async enter() {
    Utils.qs('header').style.display = 'none';
    document.body.style.overflow = 'hidden';
    Utils.qs('.container-player').classList.add('fullscreen-mode');
    if (window.ScreenRotation) {
      await ScreenRotation.setOrientation('landscape');
      Overlay.setTitle();
    }
  },

  async exit() {
    Utils.qs('header').style.display = '';
    document.body.style.overflow = '';
    Utils.qs('.container-player').classList.remove('fullscreen-mode');
    if (window.ScreenRotation) {
      await ScreenRotation.restorePrevious();
      Overlay.setTitle();
    }
  },
};

/* ============================================================
 * OVERLAY  (title + clock shown over video controls)
 * ============================================================ */
const Overlay = {
  _timeEl: null,
  _titleEl: null,
  _el: null,

  init() {
    this._timeEl = Utils.el('currentTimeDisplay');
    this._titleEl = Utils.el('animeTitleDisplay');
    this._el = Utils.el('infoOverlay');
    setInterval(() => this._tick(), 1000);
    this._tick();
  },

  _tick() {
    if (!this._timeEl) return;
    const now = new Date();
    this._timeEl.textContent =
      String(now.getHours()).padStart(2, '0') + ':' +
      String(now.getMinutes()).padStart(2, '0');
  },

  show() { this._el?.classList.add('show'); },
  hide() { this._el?.classList.remove('show'); },

  setTitle() {
    const title = State.config?.title || '';
    const ep = State.config?.ep ?? '';
    if (!title || !this._titleEl) return;

    const suffix = ` - ${ep}`;
    const overlay = Utils.el('infoOverlay');
    const timeEl = Utils.el('currentTimeDisplay');
    const available = overlay.offsetWidth - timeEl.offsetWidth - 50;

    const probe = document.createElement('span');
    probe.style.cssText = 'visibility:hidden;position:absolute;white-space:nowrap;';
    probe.style.font = window.getComputedStyle(this._titleEl).font;
    document.body.appendChild(probe);

    probe.textContent = title + suffix;
    if (probe.offsetWidth <= available) {
      this._titleEl.textContent = title + suffix;
      probe.remove();
      return;
    }

    // Binary search for best truncation
    let lo = 0, hi = title.length, best = '';
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      const test = title.slice(0, mid) + '...' + suffix;
      probe.textContent = test;
      if (probe.offsetWidth <= available) { best = test; lo = mid + 1; }
      else { hi = mid - 1; }
    }
    this._titleEl.textContent = best;
    probe.remove();
  },
};

/* ============================================================
 * BLUR  (dynamic video background)
 * ============================================================ */
const Blur = {
  _canvas: null,
  _ctx: null,
  _video: null,
  _wrapper: null,

  init(video, wrapper) {
    if (!State.blurActive) return;
    this._video = video;
    this._wrapper = wrapper;
    this._canvas = document.createElement('canvas');
    this._ctx = this._canvas.getContext('2d', { willReadFrequently: false });

    video.addEventListener('play', () => { if (State.blurLooping) { cancelAnimationFrame(State.animFrame); this._loop(); } });
    video.addEventListener('pause', () => cancelAnimationFrame(State.animFrame));

    document.addEventListener('visibilitychange', () => {
      if (document.hidden) cancelAnimationFrame(State.animFrame);
      else if (!video.paused && State.blurLooping) this._loop();
    });
  },

  _loop() {
    this._generate();
    State.animFrame = requestAnimationFrame(() => this._loop());
  },

  async _generate() {
    const now = performance.now();
    const interval = 1000 / CONFIG.BLUR.fps;
    if (State.blurFrame || this._video.paused || this._video.readyState < 2 || document.hidden || now - State.blurLastTs < interval) return;

    State.blurFrame = true;
    State.blurLastTs = now;

    try {
      const scale = CONFIG.BLUR.scale;
      const w = (this._video.videoWidth * scale) | 0 || 1;
      const h = (this._video.videoHeight * scale) | 0 || 1;

      if (this._canvas.width !== w) this._canvas.width = w;
      if (this._canvas.height !== h) this._canvas.height = h;

      try {
        if (window.createImageBitmap) {
          const bmp = await createImageBitmap(this._video, { resizeWidth: w, resizeHeight: h });
          this._ctx.clearRect(0, 0, w, h);
          this._ctx.drawImage(bmp, 0, 0);
          bmp.close();
        } else {
          this._ctx.drawImage(this._video, 0, 0, w, h);
        }
      } catch {
        this._ctx.drawImage(this._video, 0, 0, w, h);
      }

      const blob = this._canvas.convertToBlob
        ? await this._canvas.convertToBlob({ type: 'image/jpeg', quality: 0.6 })
        : await new Promise((r) => this._canvas.toBlob(r, 'image/jpeg', 0.6));

      if (!blob) { State.blurFrame = false; return; }

      const url = URL.createObjectURL(blob);
      const img = new Image();
      img.decoding = 'async';

      img.onload = () => {
        State.blurBufIdx = State.blurBufIdx === 0 ? 1 : 0;
        this._wrapper.style.setProperty('--blur-bg', `url("${url}")`);
        if (State.blurBuffers[State.blurBufIdx]) URL.revokeObjectURL(State.blurBuffers[State.blurBufIdx]);
        State.blurBuffers[State.blurBufIdx] = url;
        State.blurFrame = false;
      };
      img.onerror = () => { URL.revokeObjectURL(url); State.blurFrame = false; };
      img.src = url;

    } catch (err) {
      if (!(err instanceof DOMException)) console.error('[Blur]', err);
      State.blurFrame = false;
    }
  },
};

/* ============================================================
 * DRAGGABLE  (mini-player)
 * ============================================================ */
const Draggable = {
  _el: null,
  _active: false,
  _initX: 0,
  _initY: 0,

  init(el) {
    this._el = el;
    el.addEventListener('mousedown', (e) => this._start(e));
    el.addEventListener('touchstart', (e) => this._start(e), { passive: true });
    document.addEventListener('mouseup', () => this._end());
    document.addEventListener('touchend', () => this._end());
    document.addEventListener('mousemove', (e) => this._move(e));
    document.addEventListener('touchmove', (e) => this._move(e));
  },

  enable() { this._el?.classList.add('draggable-mode'); },
  disable() {
    this._el?.classList.remove('draggable-mode');
    if (this._el) this._el.style.transform = 'translate3d(0,0,0)';
    State.drag.x = 0;
    State.drag.y = 0;
  },

  _coords: (e) => e.type.includes('touch') ? e.touches[0] : e,

  _start(e) {
    if (!this._el?.classList.contains('draggable-mode')) return;
    const c = this._coords(e);
    this._initX = c.clientX - State.drag.x;
    this._initY = c.clientY - State.drag.y;
    this._active = true;
    this._el.classList.add('dragging');
  },

  _end() {
    this._active = false;
    this._el?.classList.remove('dragging');
  },

  _move(e) {
    if (!this._active) return;
    e.preventDefault();
    const c = this._coords(e);
    State.drag.x = c.clientX - this._initX;
    State.drag.y = c.clientY - this._initY;
    if (this._el) this._el.style.transform = `translate3d(${State.drag.x}px,${State.drag.y}px,0)`;
  },
};

/* ============================================================
 * PLYR  (player setup + events)
 * ============================================================ */
const PlyrSetup = {
  _player: null,
  _overlay: null,
  _originalParent: null,
  _plyrContainer: null,

  init() {
    const video = Utils.el('player');
    this._overlay = Utils.el('infoOverlay');
    this._originalParent = this._overlay?.parentElement;

    this._player = new Plyr('#player', {
      controls: ['play-large', 'play', 'progress', 'current-time', 'mute', 'fullscreen', 'settings'],
    });

    this._player.on('ready', () => this._onReady());
    this._player.on('enterfullscreen', () => this._onEnterFS());
    this._player.on('exitfullscreen', () => this._onExitFS());
    this._player.on('controlsshown', () => { Overlay.setTitle(); Overlay.show(); });
    this._player.on('controlshidden', () => Overlay.hide());

    return this._player;
  },

  _onReady() {
    this._plyrContainer = this._player.elements.container;
    const controls = Utils.qs('.plyr__controls');

    // Skip +1:20 button
    const skipBtn = document.createElement('button');
    skipBtn.type = 'button';
    skipBtn.className = 'plyr__control plyr__button plyr__button--skip120';
    skipBtn.setAttribute('aria-label', 'Avanzar 1:20');
    skipBtn.innerHTML = '<i class="bi bi-clock-history"></i>';
    controls.insertBefore(skipBtn, controls.children[1]);
    skipBtn.addEventListener('click', () => { this._player.currentTime += 80; });

    // Time remaining (counts down instead of up)
    const tick = () => {
      const el = Utils.qs('.plyr__time--current');
      if (el && this._player.duration) {
        const t = this._player.duration - this._player.currentTime;
        const min = Math.floor(t / 60).toString().padStart(2, '0');
        const sec = Math.floor(t % 60).toString().padStart(2, '0');
        el.textContent = `-${min}:${sec}`;
      }
      requestAnimationFrame(tick);
    };
    tick();

    // Double-tap / double-click to seek ±10s
    const wrapper = Utils.qs('.video-wrapper');
    let lastTap = 0;

    const seek = (x, w) => { this._player.currentTime += x < w / 2 ? -10 : 10; };

    wrapper.addEventListener('dblclick', (e) => {
      const r = wrapper.getBoundingClientRect();
      seek(e.clientX - r.left, r.width);
    });

    wrapper.addEventListener('touchend', (e) => {
      const now = Date.now();
      if (now - lastTap < 300 && now - lastTap > 0) {
        const r = wrapper.getBoundingClientRect();
        seek(e.changedTouches[0].clientX - r.left, r.width);
        e.preventDefault();
      }
      lastTap = now;
    });
  },

  async _onEnterFS() {
    State.fullscreen = true;
    this._plyrContainer?.appendChild(this._overlay);
    Modal.close();
    await Fullscreen.enter();
  },

  async _onExitFS() {
    State.fullscreen = false;
    this._originalParent?.appendChild(this._overlay);
    await Fullscreen.exit();
  },
};

/* ============================================================
 * THEME
 * ============================================================ */
const Theme = {
  setup(btn) {
    const set = (theme) => {
      document.body.classList.toggle('light-theme', theme === 'light');
      btn.innerHTML = theme === 'light'
        ? '<i class="bi bi-brightness-high-fill"></i>'
        : '<i class="bi bi-moon-stars-fill"></i>';
      localStorage.setItem('theme', theme);
    };

    btn.addEventListener('click', () => {
      set(document.body.classList.contains('light-theme') ? 'dark' : 'light');
    });

    set(localStorage.getItem('theme') || 'dark');
  },
};

/* ============================================================
 * WAKE LOCK
 * ============================================================ */
const WakeLock = {
  async request() {
    try {
      State.wakeLock = await navigator.wakeLock.request('screen');
      State.wakeLock.addEventListener('release', () => console.info('[WakeLock] released'));
    } catch (err) {
      console.warn('[WakeLock]', err.message);
    }
  },
};

/* ============================================================
 * SERVER BUTTONS
 * ============================================================ */
const ServerUI = {
  render(servers, onClick) {
    let container = Utils.el('serverButtons');
    if (!container) {
      const player = Utils.el('player');
      container = document.createElement('div');
      container.id = 'serverButtons';
      container.className = 'server-buttons';
      player.parentElement.insertBefore(container, player.nextSibling);
    }
    container.innerHTML = '';

    servers.forEach((server, i) => {
      const btn = document.createElement('button');
      btn.textContent = server.servidor.toUpperCase();
      btn.dataset.servidor = server.servidor;
      btn.className = 'btn server-btn';
      btn.addEventListener('click', () => onClick(server, i));
      container.appendChild(btn);
    });
  },

  highlight(index) {
    Utils.el('serverButtons')?.querySelectorAll('button').forEach((btn, i) => {
      btn.classList.toggle('active', i === index);
    });
  },

  setLoaderText(text) {
    const el = Utils.el('loaderText');
    if (el) el.innerText = text;
  },
};

/* ============================================================
 * STREAM  (HLS / MP4 / MEGA / ADS loading)
 * ============================================================ */
const Stream = {
  _cleanHls() {
    if (State.hls) {
      try { State.hls.destroy(); } catch { /* ignore */ }
      State.hls = null;
    }
    if (State.blobUrl) { URL.revokeObjectURL(State.blobUrl); State.blobUrl = null; }
  },

  _cleanProgress() {
    if (State.progressTimer !== null) {
      clearInterval(State.progressTimer);
      State.progressTimer = null;
    }
  },

  _fixM3u8(content, baseUrl) {
    return content.replace(/^(?!#)([^:\n][^\n]*)$/gm, (line) => {
      try { return new URL(line, baseUrl).href; } catch { return line; }
    });
  },

  async loadDirect(url, m3u8Content = null) {
    const video = Utils.el('player');
    const loader = Utils.el('loader');
    const slug = `${State.config.uid}-${State.config.ep}`;

    this._cleanProgress();
    this._cleanHls();

    // Remove any existing iframe
    Utils.el('megaIframe')?.remove();
    Utils.el('adsIframe')?.remove();
    video.style.display = 'block';

    let nextTriggered = false;

    if (Hls.isSupported() && (url.endsWith('.m3u8') || m3u8Content)) {
      State.hls = new Hls();
      const src = m3u8Content
        ? (State.blobUrl = URL.createObjectURL(new Blob([this._fixM3u8(m3u8Content, url)], { type: 'application/vnd.apple.mpegurl' })))
        : url;

      State.hls.loadSource(src);
      State.hls.attachMedia(video);
      State.hls.on(Hls.Events.MANIFEST_PARSED, async () => {
        loader.style.display = 'none';
        video.style.opacity = 1;
        try { await video.play(); await WakeLock.request(); } catch { /* autoplay blocked */ }
      });
    } else {
      video.src = url;
      video.load();
      video.addEventListener('loadedmetadata', async () => {
        loader.style.display = 'none';
        video.style.opacity = 1;
        try { await video.play(); await WakeLock.request(); } catch { /* autoplay blocked */ }
      }, { once: true });
    }

    // Restore saved position
    const saved = await DB.loadProgress(slug);
    if (saved > 0) { video.currentTime = saved; console.log(`[Progress] Resumed at ${saved}s`); }

    // Auto-save every 10s
    State.progressTimer = setInterval(() => {
      if (!isNaN(video.currentTime) && video.currentTime > 0) {
        DB.saveProgress(slug, Math.floor(video.currentTime));
      }
    }, 10000);

    video.addEventListener('pause', () => DB.saveProgress(slug, video.currentTime));
    window.addEventListener('beforeunload', () => DB.saveProgress(slug, video.currentTime));

    // Auto-advance to next episode
    video.addEventListener('timeupdate', async () => {
      if (!video.duration || State.config.ep >= State.config.totalEp) return;
      if (video.duration - video.currentTime <= 5 && !nextTriggered) {
        nextTriggered = true;
        await DB.saveProgress(slug, 0);
        this._cleanProgress();
        Player.loadEpisode(State.config.ep + 1);
      }
    });
  },

  async loadAds(server, container) {
    const video = Utils.el('player');
    video.pause();
    video.style.display = 'none';
    this._cleanProgress();

    Utils.el('adsIframe')?.remove();
    const iframe = document.createElement('iframe');
    iframe.src = server.url.replace('/file/', '/embed/');
    iframe.id = 'adsIframe';
    iframe.className = video.className;
    iframe.allowFullscreen = true;
    container.parentElement.insertBefore(iframe, container.nextSibling);

    container.querySelectorAll('button').forEach((btn) => {
      btn.classList.toggle('active', btn.dataset.servidor === server.servidor);
    });
    Utils.el('loader').style.display = 'none';
  },

  async loadMega(url) {
    const video = Utils.el('player');
    const loader = Utils.el('loader');
    loader.style.display = 'none';
    video.style.display = 'none';
    Utils.el('megaIframe')?.remove();

    const iframe = document.createElement('iframe');
    iframe.src = url.replace('/file/', '/embed/');
    iframe.allowFullscreen = true;
    iframe.id = 'megaIframe';
    iframe.className = video.className;
    video.parentElement.insertBefore(iframe, video);
  },
};

/* ============================================================
 * EPISODE UI  (nav + episode list)
 * ============================================================ */
const EpisodeUI = {
  render(data) {
    const nav = Utils.el('nav-buttons');
    const list = Utils.el('episode-list');
    const ep = State.config.ep;
    const PER = 12;
    let group = Math.floor((ep - 1) / PER);

    nav.innerHTML = '';
    Utils.el('anime-title').innerText = data.anime_title;

    if (ep > 1) {
      const prev = this._navBtn('<i class="bi bi-arrow-left"></i>', 'Anterior');
      prev.onclick = () => Player.loadEpisode(ep - 1);
      nav.appendChild(prev);
    }

    const home = this._navBtn('<i class="bi bi-list"></i>', 'Info');
    home.onclick = () => {
      // Expose animeInfo globally (defined in index.js / shared)
      if (typeof animeInfo === 'function') animeInfo(State.config.uid);
    };
    nav.appendChild(home);

    if (ep < data.episodes_count) {
      const next = this._navBtn('<i class="bi bi-arrow-right"></i>', 'Siguiente');
      next.onclick = () => Player.loadEpisode(ep + 1);
      nav.appendChild(next);
    }

    const info = document.createElement('span');
    info.innerText = ` Episodio ${ep} / ${data.episodes_count} `;
    nav.appendChild(info);

    const themeBtn = document.createElement('button');
    themeBtn.id = 'theme-toggle';
    themeBtn.title = 'Cambiar tema';
    themeBtn.innerHTML = '<i class="bi bi-moon-stars-fill"></i>';
    nav.appendChild(themeBtn);
    Theme.setup(themeBtn);

    const renderGroup = () => {
      list.innerHTML = '';
      const total = Math.ceil(data.episodes_count / PER);
      const start = group * PER + 1;
      const end = Math.min(start + PER - 1, data.episodes_count);

      if (group > 0) {
        const b = this._epBtn('◀');
        b.onclick = () => { group--; renderGroup(); };
        list.appendChild(b);
      }

      for (let i = start; i <= end; i++) {
        const b = this._epBtn(String(i), i === ep);
        b.onclick = () => Player.loadEpisode(i);
        list.appendChild(b);
      }

      if (group < total - 1) {
        const b = this._epBtn('▶');
        b.onclick = () => { group++; renderGroup(); };
        list.appendChild(b);
      }
    };

    renderGroup();
  },

  _navBtn(html, title) {
    const b = document.createElement('button');
    b.innerHTML = html;
    b.title = title;
    return b;
  },

  _epBtn(text, active = false) {
    const b = document.createElement('button');
    b.className = 'btn episode-btn' + (active ? ' active' : '');
    b.textContent = text;
    return b;
  },
};

/* ============================================================
 * PLAYER  (orchestrator)
 * ============================================================ */
const Player = {
  init() {
    const parts = window.location.pathname.split('/').filter(Boolean);

    // /player / id / ep
    const id = parts[1];
    const ep = parseInt(parts[2]);

    if (id && !isNaN(ep)) {
      this.loadEpisode(ep, id);
    } else {
      Utils.el('anime-title').innerText = 'Faltan parámetros';
      Utils.el('loader').style.display = 'none';
    }

    window.addEventListener('popstate', () => {
      const p = window.location.pathname.split('/').filter(Boolean);
      const i = p[1];
      const e = parseInt(p[2]);

      if (!isNaN(e) && e !== State.config.ep) {
        this.loadEpisode(e, i);
      }
    });
  },

  async loadEpisode(epNumber, idOverride = null) {
    const loader = Utils.el('loader');
    const video = Utils.el('player');

    loader.style.display = 'flex';
    video.style.opacity = 0;

    Utils.el('nav-buttons').innerHTML = '';
    Utils.el('episode-list').innerHTML = '';

    Utils.el('megaIframe')?.remove();
    Utils.el('adsIframe')?.remove();

    video.style.display = 'block';

    const parts = window.location.pathname.split('/').filter(Boolean);

    const id = idOverride || parts[1];

    if (!id || isNaN(epNumber)) {
      Utils.el('anime-title').innerText = 'Faltan parámetros';
      return;
    }

    try {
      ServerUI.setLoaderText('Cargando información…');

      const res = await fetch(
        `${CONFIG.API_BASE}/player?uid=${encodeURIComponent(id)}&ep=${epNumber}`
      );

      const data = await res.json();

      if (data.error) {
        Utils.el('anime-title').innerText = 'Error: ' + data.error;
        return;
      }

      State.config = {
        id: data.id,
        uid: data.uid_data,
        totalEp: data.episodes_count,
        ep: epNumber,
        title: data.anime_title
      };

      const newUrl = `/player/${encodeURIComponent(data.uid_data)}/${epNumber}`;
      window.history.pushState(State.config, data.anime_title, newUrl);

      document.title = data.anime_title;

      EpisodeUI.render(data);
      await this._loadStream();
    } catch (err) {
      Utils.el('anime-title').innerText = 'Error de carga.';
      console.error(err);
    }
  },

  async _loadStream(mirror = 'auto', server = 'auto') {
    const video = Utils.el('player');
    const loader = Utils.el('loader');

    Stream._cleanHls();
    Stream._cleanProgress();

    ServerUI.setLoaderText('Obteniendo servidores...');

    video.src = '';
    video.pause();

    try {
      const res = await fetch(`${CONFIG.API_BASE}/play`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          uid: State.config.uid,
          ep: State.config.ep,
          m: mirror,
          s: server
        })
      });

      const data = await res.json();

      if (!res.ok || data.error) {
        throw new Error(data.message || data.error || 'Error en play');
      }

      if (!data.servers?.length) {
        throw new Error('Sin servidores');
      }

      State.serverList = data.servers.map(s => ({ servidor: s }));

      ServerUI.render(State.serverList, (s) =>
        this._loadStream(mirror, s.servidor)
      );

      const activeIndex = State.serverList.findIndex(
        s => s.servidor === data.Sserver
      );

      ServerUI.highlight(activeIndex >= 0 ? activeIndex : 0);

      ServerUI.setLoaderText(`Cargando ${data.Sserver.toUpperCase()}...`);

      const mediaRes = await fetch(data.url);
      if (!mediaRes.ok) throw new Error('Error obteniendo media');

      if (data.mtype === 'hls') {
        const m3u8Content = await mediaRes.text();
        await Stream.loadDirect(data.url, m3u8Content);
      } else {
        const json = await mediaRes.json();
        await Stream.loadDirect(json.url);
      }

    } catch (err) {
      if (mirror === 'auto' || (typeof mirror === 'number' && mirror < 8)) {
        const nextMirror = mirror === 'auto' ? 2 : mirror + 1;
        ServerUI.setLoaderText(`Reintentando mirror ${nextMirror}...`);
        return this._loadStream(nextMirror);
      }

      console.error('[Player] Fatal:', err);
      ServerUI.setLoaderText('Error de carga. Intente de nuevo.');
      loader.style.display = 'none';
    }
  }
};

/* ============================================================
 * BOOTSTRAP
 * ============================================================ */

document.addEventListener('DOMContentLoaded', () => {
  // Overlay clock
  Overlay.init();
  // Plyr
  PlyrSetup.init();

  // Draggable mini-player
  const wrapper = Utils.qs('.video-wrapper');
  if (wrapper) {
    if (!wrapper.id) wrapper.id = 'draggable-video-wrapper';
    Draggable.init(wrapper);

    const modal = Utils.el('animeModal');
    modal?.addEventListener('show.bs.modal', () => Draggable.enable());
    modal?.addEventListener('hide.bs.modal', () => Draggable.disable());
  }

  // Blur background
  const video = Utils.el('player');
  Blur.init(video, wrapper);
  Search.init();
  MobileSearch.init();
  // Network guard → starts Player.init() once online
  Network.check();
});